import{_ as t,o as a,c as l,a0 as i}from"./chunks/framework.jwovEGr5.js";const m=JSON.parse('{"title":"Create a Custom Event","description":"","frontmatter":{},"headers":[],"relativePath":"how-to/create-custom-event.md","filePath":"how-to/create-custom-event.md"}'),o={name:"how-to/create-custom-event.md"};function n(r,e,s,c,d,h){return a(),l("div",null,[...e[0]||(e[0]=[i('<h1 id="create-a-custom-event" tabindex="-1">Create a Custom Event <a class="header-anchor" href="#create-a-custom-event" aria-label="Permalink to &quot;Create a Custom Event&quot;">​</a></h1><p>Create a custom event when none of the default templates fits exactly, or when your kingdom or alliance needs its own variation of an existing template.</p><h2 id="when-to-create-one" tabindex="-1">When to create one <a class="header-anchor" href="#when-to-create-one" aria-label="Permalink to &quot;When to create one&quot;">​</a></h2><p>A custom event is a good idea when:</p><ul><li>you track an event the app does not seed by default</li><li>you want different labels, stage rules, or visibility than the shared default</li><li>you want a kingdom-only or alliance-only version of a template</li></ul><p>If a default template is already close, you may prefer to customize or edit it instead. See <a href="./edit-event-template.html">Edit an Event Template</a>.</p><h2 id="basic-steps" tabindex="-1">Basic steps <a class="header-anchor" href="#basic-steps" aria-label="Permalink to &quot;Basic steps&quot;">​</a></h2><ol><li>Open <strong>Event Templates</strong>.</li><li>Make sure your current context is correct.</li><li>Enter the event name.</li><li>Select <strong>Add Event Template</strong>.</li><li>Open the new template and finish its settings.</li></ol><h2 id="scope-matters" tabindex="-1">Scope matters <a class="header-anchor" href="#scope-matters" aria-label="Permalink to &quot;Scope matters&quot;">​</a></h2><p>The app creates custom templates in the scope you are working in:</p><ul><li><code>Supreme Admin</code> without a selected kingdom creates a global template</li><li>a kingdom context creates a kingdom template</li><li>an alliance context creates an alliance template</li></ul><p>If you meant to create a scoped template, check your context first.</p><h2 id="after-creation" tabindex="-1">After creation <a class="header-anchor" href="#after-creation" aria-label="Permalink to &quot;After creation&quot;">​</a></h2><p>A new custom event starts simple. After that, you usually need to set:</p><ul><li>duration style</li><li>score entry mode</li><li>score labels</li><li>analytics visibility</li><li>participant policy settings</li></ul><p>Use <a href="./event-settings.html">Configure Event Settings</a> for the detailed settings page.</p><h2 id="good-practice" tabindex="-1">Good practice <a class="header-anchor" href="#good-practice" aria-label="Permalink to &quot;Good practice&quot;">​</a></h2><ul><li>create the template first</li><li>configure the rules second</li><li>create real instances only after the template behaves the way you want</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./../events/templates-overview.html">Event Templates &amp; Instances Explained</a></li><li><a href="./../events/default-events.html">The Default Events</a></li><li><a href="./edit-event-template.html">Edit an Event Template</a></li></ul>',20)])])}const u=t(o,[["render",n]]);export{m as __pageData,u as default};
